-- ── Internal state ────────────────────────────────────────────────────────────
local reported         = {}     -- ap_id -> true once returned from poll()
local server_locations = nil    -- set of ap_ids the server expects (nil = all)
local rom_ok           = nil    -- cached "SMW" header result
local mem              = {}
local log_fn           = nil

-- ── Logging ───────────────────────────────────────────────────────────────────
local function log(msg)
  if log_fn then pcall(log_fn, "[smw] " .. tostring(msg)) end
end

-- ── Memory API (resolved at init; 2-arg domain form + current-domain fallback) ─
local function resolve_memory_api()
  if not memory then return false end
  mem.read_u8  = memory.read_u8     or memory.readbyte
  mem.read_u16 = memory.read_u16_le or memory.readword
  return mem.read_u8 ~= nil
end

local function rd(fn, addr, domain)
  if not fn then return nil end
  local ok, v = pcall(fn, addr, domain)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(fn, addr)                       -- older API: current domain
  if ok and type(v) == "number" then return v end
  return nil
end

local function read_wram_u8(off)  return rd(mem.read_u8, off, WRAM) end

-- CARTROM reads with "ROM" / "System Bus" domain-name fallbacks (cores vary;
-- System Bus addresses the same LoROM byte at 0x008000-banked offsets, but the
-- raw-file-offset CARTROM/ROM form is what every SNES BizHawk core exposes).
local function read_cartrom_u8(off)
  local ok, v = pcall(mem.read_u8, off, CARTROM)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(mem.read_u8, off, "ROM")
  if ok and type(v) == "number" then return v end
  return nil
end

local function bit_and(a, b)
  -- 8/16-bit safe AND without the bit library (cores vary).
  local res, bitval = 0, 1
  while a > 0 and b > 0 do
    if a % 2 == 1 and b % 2 == 1 then res = res + bitval end
    a = math.floor(a / 2); b = math.floor(b / 2); bitval = bitval * 2
  end
  return res
end

local POW2 = { [0]=1, 2, 4, 8, 16, 32, 64, 128 }

-- ── ROM identity: the SNES header title starts with "SMW" (validate_rom) ───────
local function rom_is_ap()
  if rom_ok ~= nil then return rom_ok end
  local s = read_cartrom_u8(ROMHASH_OFF)
  local m = read_cartrom_u8(ROMHASH_OFF + 1)
  local w = read_cartrom_u8(ROMHASH_OFF + 2)
  if s == nil or m == nil or w == nil then return false end   -- not readable yet
  rom_ok = (s == string.byte("S") and m == string.byte("M") and w == string.byte("W"))
  if rom_ok then log("SMW ROM verified ('SMW' header title present)")
  else log("non-SMW ROM (no 'SMW' header) — detection idle, no reports") end
  return rom_ok
end

-- ── Multiworld context ────────────────────────────────────────────────────────
local function load_locations(ids)
  if type(ids) ~= "table" then return end
  server_locations = {}
  local n = 0
  for _, id in ipairs(ids) do
    local v = tonumber(id)
    if v then server_locations[v] = true; n = n + 1 end
  end
  log("server location set: " .. n .. " ids")
end

local function wanted(ap_id)
  if server_locations == nil then return true end   -- no set provided → report all
  return server_locations[ap_id] == true
end

-- ── Per-poll snapshots (read once per poll, matching game_watcher) ────────────
local snap = {}     -- progress / dragon / moon / 1up / bonus / blocksanity arrays
                    -- + event_data + the option gate flags, refreshed each poll

local function read_region(off, len, domain_reader)
  local t = {}
  for i = 0, len - 1 do t[i] = domain_reader(off + i) end
  return t
end

local function refresh_snapshot()
  snap.progress    = read_region(PROGRESS_DATA_OFF, 0x0F, read_wram_u8)
  snap.dragon      = read_region(DRAGON_COINS_OFF,  0x0C, read_wram_u8)
  snap.moon        = read_region(MOON_DATA_OFF,     0x0C, read_wram_u8)
  snap.hidden_1up  = read_region(HIDDEN_1UP_OFF,    0x0C, read_wram_u8)
  snap.bonus_block = read_region(BONUS_BLOCK_OFF,   0x0C, read_wram_u8)
  -- event_data is per-seed-baked ROM; read all 0x60 once per poll from CARTROM.
  snap.event       = read_region(EVENT_ROM_OFF,     0x60, read_cartrom_u8)
  -- Option gate flags (CARTROM): a check type is only collectible if enabled.
  snap.dragon_on      = (read_cartrom_u8(DRAGON_ACTIVE_OFF)     or 0) ~= 0
  snap.moon_on        = (read_cartrom_u8(MOON_ACTIVE_OFF)       or 0) ~= 0
  snap.hidden_1up_on  = (read_cartrom_u8(HIDDEN_1UP_ACTIVE_OFF) or 0) ~= 0
  snap.bonus_on       = (read_cartrom_u8(BONUS_ACTIVE_OFF)      or 0) ~= 0
  snap.blocksanity_on = (read_cartrom_u8(BLOCKSANITY_ACT_OFF)   or 0) ~= 0
end

-- A single bit (MSB-first within the byte, exactly as Client.py: bit 7 - n%8).
local function flag_bit(arr, bit_index)
  local byte = arr[math.floor(bit_index / 8)]
  if byte == nil then return false end
  return bit_and(byte, POW2[7 - (bit_index % 8)]) ~= 0
end

-- ── One location's "checked?" test (mirrors game_watcher per check_type) ──────
local function location_checked(level_id, check_type)
  if check_type == T_DRAGON then
    if not snap.dragon_on then return false end
    return flag_bit(snap.dragon, level_id)
  elseif check_type == T_MOON then
    if not snap.moon_on then return false end
    return flag_bit(snap.moon, level_id)
  elseif check_type == T_HIDDEN_1UP then
    if not snap.hidden_1up_on then return false end
    return flag_bit(snap.hidden_1up, level_id)
  elseif check_type == T_BONUS_BLOCK then
    if not snap.bonus_on then return false end
    return flag_bit(snap.bonus_block, level_id)
  elseif check_type >= T_BLOCKSANITY_BASE then
    if not snap.blocksanity_on then return false end
    local idx = check_type - T_BLOCKSANITY_BASE
    local b = read_wram_u8(BLOCKSANITY_OFF + idx)   -- flat byte, 582-wide region
    return b ~= nil and b ~= 0
  else
    -- Standard level exit (type 0 or 1).
    local event_id = snap.event[level_id]
    if event_id == nil then return false end
    local ev = event_id + check_type
    return flag_bit(snap.progress, ev)
  end
end

-- ── Detection gate ────────────────────────────────────────────────────────────
local function game_state() return read_wram_u8(GAME_STATE_OFF) end

local function in_gameplay()
  local s = game_state()
  -- Client.py: <0x0B → no save loaded (idle); >0x29 → left the file. The 0x18..
  -- 0x29 ending range is still scanned for checks (and is where the goal fires).
  return s ~= nil and s >= STATE_SAVE_LOADED and s <= STATE_MAX
end

-- ── Module contract ───────────────────────────────────────────────────────────
function M.init(ctx)
  if ctx and type(ctx.log) == "function" then log_fn = ctx.log end
  if not resolve_memory_api() then
    log("BizHawk memory API unavailable — module idle")
    ADDRESSES_VERIFIED = false
    return
  end
  local cfg = (ctx and ctx.config) or {}
  load_locations(cfg.locations)
  local n = 0; for _ in pairs(LOC) do n = n + 1 end
  log("ready: " .. n .. " location flags (items_handling=0b111; receive_item is a "
      .. "documented no-op pending in-emulator verification)")
end

function M.poll()
  local new = {}
  if not ADDRESSES_VERIFIED then return new end
  if not rom_is_ap() then return new end
  if not in_gameplay() then return new end
  refresh_snapshot()
  for ap_id, ld in pairs(LOC) do
    if not reported[ap_id] and wanted(ap_id) and location_checked(ld[1], ld[2]) then
      reported[ap_id] = true
      new[#new + 1] = ap_id
    end
  end
  return new
end

function M.is_goal_complete()
  if not ADDRESSES_VERIFIED or not rom_is_ap() then return false end
  local s = game_state()
  if s == nil or s < GOAL_STATE_MIN then return false end
  local lvl = read_wram_u8(CURRENT_LEVEL_OFF)
  return lvl ~= nil and GOAL_LEVELS[lvl] == true
end

-- Remote multiworld items: see the file header. items_handling = 0b111 means the
-- SMW client owns ALL item delivery — there is no game-self-grant fallback. The
-- delivery path is an intricate per-item-type set of guarded WRAM writes gated on
-- a recv-progress counter and precise game/Mario/boss/message states. It is the
-- one piece deferred until it can be confirmed in-emulator. No-op (never a wrong
-- write) until then; checks + goal above are fully functional regardless.
function M.receive_item(item_id, meta)
  -- intentionally empty (documented)
end

return M
